  agriculture_farming: {
    name: "Landwirtschaft und Anbau",
    description: "Landwirtschaftliche Tätigkeiten und Anbaumethoden",
    icon: Sprout,
    color: "from-green-500 to-lime-600",
    level: "beginner",
    words: [
      { id: "ge_agri_1", german: "Bauernhof", english: "Farm", difficulty: "easy", example: "The family farm produces fresh vegetables fruits and dairy products for local markets and communities", exampleTranslation: "Der Familienbauernhof produziert frisches Gemüse Obst und Milchprodukte für lokale Märkte und Gemeinschaften" },
      { id: "ge_agri_2", german: "Bauer", english: "Farmer", difficulty: "easy", example: "Farmers work hard cultivating crops raising livestock and providing food for society throughout the year", exampleTranslation: "Bauern arbeiten hart kultivieren Feldfrüchte züchten Vieh und versorgen die Gesellschaft das ganze Jahr über mit Nahrung" },
      { id: "ge_agri_3", german: "Ernte", english: "Harvest", difficulty: "easy", example: "Harvest time is the busiest season when farmers gather mature crops from fields for market and storage", exampleTranslation: "Die Erntezeit ist die geschäftigste Saison wenn Bauern reife Feldfrüchte von Feldern für Markt und Lagerung sammeln" },
      { id: "ge_agri_4", german: "Feld", english: "Field", difficulty: "easy", example: "Farmers plow and prepare fields in spring planting seeds that will grow into crops by autumn", exampleTranslation: "Bauern pflügen und bereiten Felder im Frühling vor pflanzen Samen die bis zum Herbst zu Feldfrüchten wachsen werden" },
      { id: "ge_agri_5", german: "Traktor", english: "Tractor", difficulty: "easy", example: "Modern tractors help farmers work more efficiently plowing planting and harvesting large areas quickly", exampleTranslation: "Moderne Traktoren helfen Bauern effizienter zu arbeiten und große Flächen schnell zu pflügen zu pflanzen und zu ernten" },
      { id: "ge_agri_6", german: "Vieh", english: "Livestock", difficulty: "easy", example: "Raising livestock including cattle pigs and chickens provides meat dairy and other animal products", exampleTranslation: "Viehzucht einschließlich Rinder Schweine und Hühner liefert Fleisch Milchprodukte und andere tierische Produkte" },
      { id: "ge_agri_7", german: "Dünger", english: "Fertilizer", difficulty: "medium", example: "Organic and chemical fertilizers enrich soil with nutrients helping crops grow stronger and yield better harvests", exampleTranslation: "Organische und chemische Dünger reichern Erde mit Nährstoffen an helfen Feldfrüchten stärker zu wachsen und bessere Ernten zu erzielen" },
      { id: "ge_agri_8", german: "Bewässerung", english: "Irrigation", difficulty: "medium", example: "Irrigation systems supply water to crops in dry regions enabling agriculture in areas with insufficient natural rainfall", exampleTranslation: "Bewässerungssysteme versorgen Feldfrüchte in trockenen Regionen mit Wasser und ermöglichen Landwirtschaft in Gebieten mit unzureichendem natürlichem Niederschlag" },
      { id: "ge_agri_9", german: "Pflügen", english: "Plowing", difficulty: "medium", example: "Plowing turns over soil preparing it for planting by breaking up compacted earth and mixing in nutrients", exampleTranslation: "Pflügen wendet Erde um bereitet sie für das Pflanzen vor indem es verdichtete Erde aufbricht und Nährstoffe einmischt" },
      { id: "ge_agri_10", german: "Aussaat", english: "Sowing", difficulty: "medium", example: "Sowing seeds at the right time and depth is crucial for successful crop germination and healthy plant growth", exampleTranslation: "Samen zur richtigen Zeit und Tiefe auszusäen ist entscheidend für erfolgreiche Keimung und gesundes Pflanzenwachstum" },
      { id: "ge_agri_11", german: "Scheune", english: "Barn", difficulty: "medium", example: "Barns provide shelter for animals storage for hay equipment and protection from weather on farms", exampleTranslation: "Scheunen bieten Schutz für Tiere Lagerung für Heu und Ausrüstung und Schutz vor Wetter auf Bauernhöfen" },
      { id: "ge_agri_12", german: "Jahreszeit", english: "Season", difficulty: "medium", example: "Agricultural activities follow seasonal cycles with planting in spring growing in summer and harvesting in autumn", exampleTranslation: "Landwirtschaftliche Aktivitäten folgen jahreszeitlichen Zyklen mit Pflanzen im Frühling Wachstum im Sommer und Ernte im Herbst" },
      { id: "ge_agri_13", german: "Die Ernte war ertragreich", english: "The harvest was bountiful", difficulty: "hard", example: "The harvest was incredibly bountiful this year! Perfect weather and good farming practices produced exceptional crop yields!", exampleTranslation: "Die Ernte war dieses Jahr unglaublich ertragreich! Perfektes Wetter und gute Anbaumethoden produzierten außergewöhnliche Erträge!" },
      { id: "ge_agri_14", german: "Nachhaltige Landwirtschaft", english: "Sustainable agriculture", difficulty: "hard", example: "Sustainable agriculture practices protect soil quality conserve water and maintain long-term productive farming without environmental degradation!", exampleTranslation: "Nachhaltige Landwirtschaftspraktiken schützen Bodenqualität bewahren Wasser und erhalten langfristig produktive Landwirtschaft ohne Umweltzerstörung!" },
      { id: "ge_agri_15", german: "Agrarwirtschaft", english: "Agricultural economy", difficulty: "hard", example: "Agricultural economy remains vital globally providing food employment and raw materials supporting both rural and urban populations!", exampleTranslation: "Agrarwirtschaft bleibt global vital liefert Nahrung Beschäftigung und Rohstoffe die sowohl ländliche als auch städtische Bevölkerungen unterstützen!" }
    ]
  },

